                outHtml += `<div><span style="color:var(--midea-dark);">${ws}</span><b>${wsAgg[ws].o}</b></div>`; upphHtml += `<div><span style="color:var(--midea-dark);">${ws}</span><b class="${wUpph>=23?'val-success':'val-danger'}">${wUpph}</b></div>`;
